    let string_calculator = CALCULATOR(
        [
            ("+", STRING_CONCATENATION()),
            ("-", STRING_SUBTRACTION())
        ]
    );

    let concatenated =
        string_calculator.calculate("+", "hello", "world");
    write_line("hello + world = {concatenated}");

